import{_ as s}from"./chunks/lab-2-1.BIoSFs8y.js";import{_ as c,C as r,o as d,c as h,a3 as a,G as i,w as p,j as t,a as o}from"./chunks/framework.DBrjlGeB.js";const g="/Python-Programming/assets/lab-4-1.9iD4Pc8e.png",u="/Python-Programming/assets/lab-4-2.CesYdZdl.png",m="/Python-Programming/assets/lab-4-3.QzwDUxOL.png",b="/Python-Programming/assets/lab-4-4.CKnOHMn7.png",f="/Python-Programming/assets/lab-4-5.Bq5dmaXH.png",w="/Python-Programming/assets/lab-4-6.IOICfhzA.png",y="/Python-Programming/assets/lab-4-7.D6wRw84M.png",P="/Python-Programming/assets/lab-4-8.DslLSdU6.png",R=JSON.parse('{"title":"Lab 4 - Selection in Flowgorithm","description":"","frontmatter":{"outline":"deep","title":"Lab 4 - Selection in Flowgorithm"},"headers":[],"relativePath":"labs/lab-04.md","filePath":"labs/lab-04.md"}'),_={name:"labs/lab-04.md"},k={id:"scenario-1-electricity-bill",tabindex:"-1"},T={id:"scenario-2-income-tax-slab",tabindex:"-1"},x={id:"scenario-3-parking-fee",tabindex:"-1"},S={id:"scenario-4-baggage-allowance-logic",tabindex:"-1"};function v(C,e,A,I,N,q){const l=r("Checklist"),n=r("Badge");return d(),h("div",null,[e[13]||(e[13]=a('<h1 id="lab-04-selection-in-flowgorithm" tabindex="-1">Lab 04 : Selection in Flowgorithm <a class="header-anchor" href="#lab-04-selection-in-flowgorithm" aria-label="Permalink to &quot;Lab 04 : Selection in Flowgorithm&quot;">​</a></h1><h2 id="before-you-begin" tabindex="-1">Before You Begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before You Begin&quot;">​</a></h2><p>Same as every lab, before you start, make sure your workspace and login are <strong>yours</strong>:</p><ol><li>Open <strong>your own</strong> cloned folder in <strong>VS Code</strong> (<code>File</code> → <code>Open Folder...</code>). Many students share the same PC, so confirm the folder belongs to you.</li><li>In the terminal, log out of any account with <code>gh auth logout</code>, then log back in as yourself with <code>gh auth login</code>.</li></ol><p>Full steps are in <a href="./lab-02.html#before-you-begin">Lab 02 - Before You Begin</a> if you need a reminder.</p><h2 id="pull-and-update-in-vs-code" tabindex="-1">Pull and Update in VS Code <a class="header-anchor" href="#pull-and-update-in-vs-code" aria-label="Permalink to &quot;Pull and Update in VS Code&quot;">​</a></h2><p>This lab builds on <a href="./lab-03.html">Lab 03</a>. There you learned the <strong>process</strong> structure: adding the <code>Assign</code> shape to calculate values, running your flowchart, and exporting it to <strong>Python</strong>. Here you will add the missing piece, <strong>selection</strong>, so your flowchart can make decisions and take different paths depending on the input.</p><p>Before starting any lab, you need to make sure that the repo in your <strong>GitHub</strong> is the latest one. <a href="./lab-01.html#syncing-fork">Sync the repo</a> if the <code>upstream</code> repo have been updated.</p><p>Once the online repo is in-sync, bring those changes down to your PC by clicking <code>Source Control</code> and then <code>...</code> beside <code>Changes</code> and click <a href="./glossary.html#pull"><code>Pull</code></a>.</p><p align="center"><img src="'+s+'" alt="drawing" width="400"></p><h2 id="checklist-before-you-proceed" tabindex="-1">Checklist Before You Proceed <a class="header-anchor" href="#checklist-before-you-proceed" aria-label="Permalink to &quot;Checklist Before You Proceed&quot;">​</a></h2>',11)),i(l,{title:"Please Check Properly"},{default:p(()=>[...e[0]||(e[0]=[t("ol",null,[t("li",null,"You have logged in to your Github account in the browser."),t("li",null,"You have logged in to your Github account in the terminal using VS Code."),t("li",null,"You have sync the repo in you Github account in the browser."),t("li",null,"You have pull the update into you repo in VS Code.")],-1)])]),_:1}),e[14]||(e[14]=a('<h2 id="implementing-selection" tabindex="-1">Implementing Selection <a class="header-anchor" href="#implementing-selection" aria-label="Permalink to &quot;Implementing Selection&quot;">​</a></h2><p>Selection in flowchart is represented by the diamond shape. In <strong>Flowgorithm</strong>, it is the same. Before we start using the diamond shapes, lets use one example from <a href="./../tutorials/chapter-3-tutorial-4.html">Tutorial 4</a> for us to implement in <strong>Flowgorithm</strong></p><blockquote><p>MyHealth magazine is sold at RM5.00 each if at least 5 units of the magazine are purchased, and it is sold at the price of RM7.00 each otherwise. Calculate the price a customer has to pay after they enter the quantity of the magazines that they purchased.</p></blockquote><p>Lets skip the <code>Input</code> shape and <code>Declare</code> shape for the questions, if you forgot how to do that, you can refer back <a href="./lab-03.html#recap-building-the-sequence">here</a>.</p><p>After declaring input and accepting input from the user, you will got this</p><p align="center"><img src="'+g+'" alt="drawing" width="300"></p><p>You have one input, the <code>magazinesNumber</code>.This is a simple selection (if–else) problem: if <code>magazinesNumber</code> ≥ 5, the unit price is RM5.00. Otherwise, the unit price is RM7.00. Note the boundary case that &quot;at least 5&quot; , so you must includes 5.</p><p>Now that we have establish the structure of the algorithm, we have discovered a new variable, which is <code>unitPrice</code>. Declare the variable using the <code>Declare</code> shape just under the input.</p><p align="center"><img src="'+u+'" alt="drawing" width="300"></p><p>The selection will be added after the <code>unitPrice</code> have been declared, The reason we did this is so that we only need to declare it once. If we declared the variable after the selection, we will have to declare it two times, one after the <code>True</code> condition and one after the <code>False</code> condition.</p><p>To add the selection, click the arrow underneath <code>unitPrice</code> and a popup window will open. Under the <strong>Control</strong> section, click the <code>Diamond</code> shape.</p><p align="center"><img src="'+m+'" alt="drawing" width="500"></p><p>The <code>Diamond</code> shape will automatically have two arrow coming out of them. The left one is for false and the right one for true.</p><p align="center"><img src="'+b+'" alt="drawing" width="300"></p><p>Double click the <code>Diamond</code> shape and a popup window will appear that will prompt you to enter condition of the expression. For our questions, we will enter <code>magazineNumber &gt;= 5</code> as our condition.</p><p align="center"><img src="'+f+'" alt="drawing" width="400"></p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>Only variable that have been declared can be used in the conditions. Make sure you declared all the necessary variable that you are going to need. Any condition inside the <code>Diamond</code> must be either evaluated to <code>True</code> or <code>False</code>.</p></div><p>Now we need to add the logic for both paths of the selection:</p><p><strong>True Path (Right Side):</strong> If <code>magazineNumber &gt;= 5</code> is <strong>True</strong>, this means the customer is buying 5 or more magazines, so they get the discounted price. We need to set <code>unitPrice = 5</code>.</p><p><strong>False Path (Left Side):</strong> If <code>magazineNumber &gt;= 5</code> is <strong>False</strong>, this means the customer is buying fewer than 5 magazines, so they pay the regular price. We need to set <code>unitPrice = 7</code>.</p><p>Click on the <strong>True</strong> arrow (right side) and add an <code>Assign</code> shape. Set the assignment to <code>unitPrice = 5</code>.</p><p>Click on the <strong>False</strong> arrow (left side) and add an <code>Assign</code> shape. Set the assignment to <code>unitPrice = 7</code>.</p><p align="center"><img src="'+w+'" alt="drawing" width="400"></p><p>After both paths, the flowchart will merge back together (note the circle connector in the image), and you can continue with calculating the total price by multiplying <code>unitPrice</code> with <code>magazineNumber</code>.</p><p>After the selection structure, we need to complete the flowchart. First, declare a new variable called <code>finalPrice</code> using the <code>Declare</code> shape to store the calculated total cost.</p><p>Next, add an <code>Assign</code> shape to calculate the final price using the formula <code>finalPrice = magazineNumber * unitPrice</code>. This will multiply the number of magazines by the unit price we determined from the selection.</p><p>Finally, add an <code>Output</code> shape to display the <code>finalPrice</code> to the user.</p><p align="center"><img src="'+y+'" alt="drawing" width="400"></p><p>The complete flowchart shows how the selection structure works:</p><ul><li>The diamond shape evaluates the condition <code>magazineNumber &gt;= 5</code></li><li>If <strong>True</strong> (right path): <code>unitPrice = 5</code></li><li>If <strong>False</strong> (left path): <code>unitPrice = 7</code></li><li>Both paths merge back together at the circle connector</li><li>Then the final calculation and output steps are executed</li></ul><h2 id="exporting-flowgorithm-to-image" tabindex="-1">Exporting Flowgorithm to Image <a class="header-anchor" href="#exporting-flowgorithm-to-image" aria-label="Permalink to &quot;Exporting Flowgorithm to Image&quot;">​</a></h2><p>At the top bar, click <strong>Tools &gt; Export to an Image file</strong>.</p><p align="center"><img src="'+P+'" alt="drawing" width="400"></p><p>After you click it, a popup window will appear, no need to change anything and just click <strong>Create</strong> atthe bottom right of the window.</p><p>Then it will prompt you the location that you want the image saved and the name of the image. Rename the image to <code>lab-4-0</code> and save it in <code>/labs/lab04/example/</code>. Also export this walkthrough to <strong>Python</strong> and save it as <code>lab-4-0.py</code> in the same folder.</p><p>For every question in this lab you submit two files: the flowchart exported as a <strong>PNG image</strong> (<code>.png</code>), and the flowchart exported as a <strong>Python file</strong> (<code>.py</code>). To create the Python file, export the flowchart the same way you learned in <a href="./lab-03.html#exporting-flowgorithm-to-python">Lab 03 - Exporting Flowgorithm to Python</a>. Save both into that question&#39;s folder, using the names given in the question.</p><h2 id="selection-questions" tabindex="-1">Selection Questions <a class="header-anchor" href="#selection-questions" aria-label="Permalink to &quot;Selection Questions&quot;">​</a></h2>',37)),t("h3",k,[e[1]||(e[1]=o("Scenario 1 - Electricity Bill ",-1)),i(n,{type:"warning",text:"Question"}),e[2]||(e[2]=o()),e[3]||(e[3]=t("a",{class:"header-anchor",href:"#scenario-1-electricity-bill","aria-label":'Permalink to "Scenario 1 - Electricity Bill <Badge type="warning" text="Question" />"'},"​",-1))]),e[15]||(e[15]=a("<p>A utility company charges RM0.30 per kWh for the first 100 kWh, RM0.50 per kWh for the next 100 kWh (101–200 kWh), and RM0.75 per kWh for any usage above 200 kWh.</p><p>Calculate the total bill when the customer enters their total kWh consumed.</p><p>Inputs (in order):</p><ul><li><code>kwh</code> – total kWh consumed</li></ul><p>Outputs (in order):</p><ul><li><code>totalBill</code> – the total electricity bill</li></ul><p>Save the PNG image as <code>lab-4-1.png</code> and the Python file as <code>lab-4-1.py</code>, both in <code>/labs/lab04/exercise1/</code>.</p>",7)),t("h3",T,[e[4]||(e[4]=o("Scenario 2 - Income Tax Slab ",-1)),i(n,{type:"warning",text:"Question"}),e[5]||(e[5]=o()),e[6]||(e[6]=t("a",{class:"header-anchor",href:"#scenario-2-income-tax-slab","aria-label":'Permalink to "Scenario 2 - Income Tax Slab <Badge type="warning" text="Question" />"'},"​",-1))]),e[16]||(e[16]=a("<p>Income tax is applied as:</p><ul><li><p>First RM50,000.00 → 0%</p></li><li><p>Next RM50,000.00 → 1%</p></li><li><p>Above RM100,000.00 → 2%</p></li></ul><p>Given an annual income, calculate total tax due.</p><p>Inputs (in order):</p><ul><li><code>income</code> – annual income (RM)</li></ul><p>Outputs (in order):</p><ul><li><code>totalTax</code> – the total tax due</li></ul><p>Save the PNG image as <code>lab-4-2.png</code> and the Python file as <code>lab-4-2.py</code>, both in <code>/labs/lab04/exercise2/</code>.</p>",8)),t("h3",x,[e[7]||(e[7]=o("Scenario 3 - Parking Fee ",-1)),i(n,{type:"warning",text:"Question"}),e[8]||(e[8]=o()),e[9]||(e[9]=t("a",{class:"header-anchor",href:"#scenario-3-parking-fee","aria-label":'Permalink to "Scenario 3 - Parking Fee <Badge type="warning" text="Question" />"'},"​",-1))]),e[17]||(e[17]=a("<p>A mall charges parking as follows:</p><p>First 2 hours → Free</p><p>Next 3 hours (2–5 hours) → RM2.00 per hour</p><p>Beyond 5 hours → RM3.00 per hour</p><p>Maximum charge per day → RM30.00</p><p>Given total hours parked, calculate the parking fee.</p><p>Inputs (in order):</p><ul><li><code>hours</code> – total hours parked</li></ul><p>Outputs (in order):</p><ul><li><code>parkingFee</code> – the parking fee (capped at RM30.00)</li></ul><p>Save the PNG image as <code>lab-4-3.png</code> and the Python file as <code>lab-4-3.py</code>, both in <code>/labs/lab04/exercise3/</code>.</p>",11)),t("h3",S,[e[10]||(e[10]=o("Scenario 4 - Baggage Allowance Logic ",-1)),i(n,{type:"warning",text:"Question"}),e[11]||(e[11]=o()),e[12]||(e[12]=t("a",{class:"header-anchor",href:"#scenario-4-baggage-allowance-logic","aria-label":'Permalink to "Scenario 4 - Baggage Allowance Logic <Badge type="warning" text="Question" />"'},"​",-1))]),e[18]||(e[18]=a("<p>A flight ticket that includes 15 kg of free baggage.Excess baggage is charged RM4.00 per kg beyond that limit. However, if the passenger brings no baggage, they receive a RM10.00 discount on the total ticket price.</p><p>Given the weight of baggage and ticket price, calculate the final price.</p><p>Inputs (in order):</p><ul><li><p><code>weight</code> – baggage weight in kg</p></li><li><p><code>ticketPrice</code> – ticket price (RM)</p></li></ul><p>Outputs (in order):</p><ul><li><code>finalPrice</code> – the final price to pay</li></ul><p>Save the PNG image as <code>lab-4-4.png</code> and the Python file as <code>lab-4-4.py</code>, both in <code>/labs/lab04/exercise4/</code>.</p>",7))])}const M=c(_,[["render",v]]);export{R as __pageData,M as default};
